        mHdltvoutHandle << " , " <<  " \"layer17_out_3_V\" :  \"" << layer17_out_3_V.read() << "\" ";
        mHdltvoutHandle << " , " <<  " \"layer17_out_4_V\" :  \"" << layer17_out_4_V.read() << "\" ";
